import { useState } from 'react';
import leadService from '../../services/leadService';

const inputClasses = "w-full px-4 py-3 border border-white/20 bg-white/10 text-white placeholder-white/60 rounded-xl focus:ring-2 focus:ring-white/50 focus:border-transparent outline-none transition-all";
const selectClasses = "w-full px-4 py-3 border border-white/20 bg-white/10 text-white rounded-xl focus:ring-2 focus:ring-white/50 focus:border-transparent outline-none transition-all appearance-none cursor-pointer";
const selectOptionClasses = "bg-gray-900 text-white";
const labelClasses = "block text-sm font-medium text-white/90 mb-2";

export default function Hero() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    company: '',
    status: '',
    turnover: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      await leadService.createLead(formData);
      setIsSuccess(true);
      setFormData({ name: '', email: '', phone: '', company: '', status: '', turnover: '' });
    } catch (err) {
      setError(err.message || 'Une erreur est survenue lors de l\'envoi du formulaire');
    } finally {
      setIsSubmitting(false);
    }
  };

return (
    <section className="relative bg-gradient-to-br from-purple-900 via-blue-800 to-purple-900 text-white pt-12 pb-16 md:pt-20 md:pb-24 overflow-hidden">
      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-8 lg:gap-16 items-center">
          <div className="relative order-2 lg:order-1">
            <img 
              src="https://lh5.googleusercontent.com/proxy/wxlzs8DUBI_YvHtAizh3wPEjJVDY00EdYEYs6D7curfCysucXqH8_ntuHONF2WJ1_46hunm4AXk8Xdg2F2DqE4s9i7Y7B_J_nTcNO2pTHhDh1oUaQlLV-HyGinrhAgBciMCMg0AEaDFs9ZupQattlppPommlKEdoICIzldXN_hJ-774Lk2gciBq8oDvZm3GE2nR5R5xRkeY82i0ry0Wd6LNJ" 
              alt="Assurance décennale electricien" 
              className="w-full max-w-sm sm:max-w-md mx-auto lg:mx-0 h-auto rounded-2xl shadow-2xl"
            />
          </div>

          <div id="quote" className="order-1 lg:order-2">
            {isSuccess ? (
              <div className="relative">
                <div className="absolute -inset-4 bg-gray-400/20 rounded-3xl blur-2xl"></div>
                <div className="relative bg-white text-gray-900 p-6 sm:p-8 rounded-2xl shadow-2xl text-center">
                  <div className="w-14 h-14 sm:w-16 sm:h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                    <svg className="w-7 h-7 sm:w-8 sm:h-8 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                  <h3 className="text-xl sm:text-2xl font-bold text-gray-900 mb-2">Merci !</h3>
                  <p className="text-gray-600 text-sm sm:mb-4">
                    Votre demande a été transmise. Un expert vous contactera sous 24h pour votre devis personnalisé d'assurance décennale.
                  </p>
                  <button onClick={() => setIsSuccess(false)} className="text-blue-800 font-medium hover:underline text-sm">
                    Envoyer une autre demande
                  </button>
                </div>
              </div>
            ) : (
              <div className="relative">
                <div className="absolute -inset-4 bg-gray-400/20 rounded-3xl blur-2xl"></div>
                <div className="relative bg-white/10 backdrop-blur-sm border border-white/20 text-white p-5 sm:p-6 md:p-8 rounded-2xl shadow-2xl">
                  <div className="text-center mb-5 sm:mb-6">
                    <h3 className="text-lg sm:text-xl md:text-2xl font-bold">Devis Gratuit</h3>
                  </div>

                  {error && (
                    <div className="mb-4 p-3 bg-red-500/20 border border-red-500/50 rounded-lg text-red-200 text-sm">
                      {error}
                    </div>
                  )}
                  <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid sm:grid-cols-2 gap-4">
                      <div>
                        <label htmlFor="hero-name" className={labelClasses}>Nom complet *</label>
                        <input
                          type="text"
                          id="hero-name"
                          name="name"
                          required
                          value={formData.name}
                          onChange={handleChange}
                          className={inputClasses}
                          placeholder="Votre nom"
                        />
                      </div>
                      <div>
                        <label htmlFor="hero-email" className={labelClasses}>Email *</label>
                        <input
                          type="email"
                          id="hero-email"
                          name="email"
                          required
                          value={formData.email}
                          onChange={handleChange}
                          className={inputClasses}
                          placeholder="votre@email.com"
                        />
                      </div>
                    </div>

                    <div className="grid md:grid-cols-2 gap-4">
                      <div>
                        <label htmlFor="hero-phone" className={labelClasses}>Téléphone *</label>
                        <input
                          type="tel"
                          id="hero-phone"
                          name="phone"
                          required
                          value={formData.phone}
                          onChange={handleChange}
                          className={inputClasses}
                          placeholder="06 12 34 56 78"
                        />
                      </div>
                      <div>
                        <label htmlFor="hero-company" className={labelClasses}>Entreprise</label>
                        <input
                          type="text"
                          id="hero-company"
                          name="company"
                          value={formData.company}
                          onChange={handleChange}
                          className={inputClasses}
                          placeholder="Nom de votre société"
                        />
                      </div>
                    </div>

                    <div className="grid sm:grid-cols-2 gap-4">
                      <div>
                        <label htmlFor="hero-status" className={labelClasses}>Statut *</label>
                        <div className="relative">
                          <select
                            id="hero-status"
                            name="status"
                            required
                            value={formData.status}
                            onChange={handleChange}
                            className={selectClasses}
                          >
                            <option value="" className={selectOptionClasses}>Sélectionner...</option>
                            <option value="auto-entrepreneur" className={selectOptionClasses}>Auto-entrepreneur</option>
                            <option value="artisan" className={selectOptionClasses}>Artisan</option>
                            <option value="sarl" className={selectOptionClasses}>SARL</option>
                            <option value="eurl" className={selectOptionClasses}>EURL</option>
                            <option value="sa" className={selectOptionClasses}>SA</option>
                            <option value="other" className={selectOptionClasses}>Autre</option>
                          </select>
                          <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                            <svg className="w-4 h-4 text-white/60" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                            </svg>
                          </div>
                        </div>
                      </div>
                      <div>
                        <label htmlFor="hero-turnover" className={labelClasses}>Chiffre d'affaires</label>
                        <div className="relative">
                          <select
                            id="hero-turnover"
                            name="turnover"
                            value={formData.turnover}
                            onChange={handleChange}
                            className={selectClasses}
                          >
                            <option value="" className={selectOptionClasses}>Sélectionner...</option>
                            <option value="0-30k" className={selectOptionClasses}>Moins de 30 000€</option>
                            <option value="30-60k" className={selectOptionClasses}>30 000€ - 60 000€</option>
                            <option value="60-100k" className={selectOptionClasses}>60 000€ - 100 000€</option>
                            <option value="100-250k" className={selectOptionClasses}>100 000€ - 250 000€</option>
                            <option value="250k+" className={selectOptionClasses}>Plus de 250 000€</option>
                          </select>
                          <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                            <svg className="w-4 h-4 text-white/60" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                            </svg>
                          </div>
                        </div>
                      </div>
                    </div>

                    <button
                      type="submit"
                      disabled={isSubmitting}
                      className="w-full bg-white text-purple-900 font-bold py-3 sm:py-4 px-4 sm:px-6 rounded-xl transition-colors hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 text-sm sm:text-base"
                    >
                      {isSubmitting ? (
                        <>
                          <svg className="animate-spin h-4 w-4 sm:h-5 sm:w-5" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                          </svg>
                          Envoi...
                        </>
                      ) : (
                        'Obtenir mon devis'
                      )}
                    </button>

                    <p className="text-center text-xs text-blue-200">
                      🔒 Vos données sont protégées. Conformément au RGPD.
                    </p>
                  </form>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-white to-transparent"></div>
    </section>
  );
}
